// RAG retrieval (§4b — the real skill). This is the SINGLE gate that decides
// which few memories reach the answer step. It enforces the hard rule: never
// more than `k` (default 8) memories are ever returned, so a user with 3 years
// of history feeds the LLM the same small amount as a user with 3 days.
//
// The scorer is a mock "embedding + vector search": token-overlap similarity
// with taste tags weighted. The real seam is an embedding API + vector store;
// `retrieve()` keeps the same signature so swapping it in is local.

import type { Memory, Retrieved } from "./types";

const DEFAULT_K = 8;
const MAX_K = 10; // hard ceiling — never feed more than this to the LLM

// Tokenise for CJK + latin: latin words, CJK unigrams, and CJK bigrams (bigrams
// capture "米線", "拉麵", "燒味" etc. better than single chars).
function tokenize(text: string): string[] {
  const s = (text || "").toLowerCase();
  const tokens: string[] = [];
  const latin = s.match(/[a-z0-9]+/g);
  if (latin) tokens.push(...latin);
  const cjk = s.match(/[一-鿿]/g) || [];
  for (let i = 0; i < cjk.length; i++) {
    tokens.push(cjk[i]);
    if (i + 1 < cjk.length) tokens.push(cjk[i] + cjk[i + 1]);
  }
  return tokens;
}

function bag(tokens: string[]): Map<string, number> {
  const m = new Map<string, number>();
  for (const t of tokens) m.set(t, (m.get(t) || 0) + 1);
  return m;
}

// A memory's searchable text + its taste tags (tags carry extra weight).
function memoryFields(mem: Memory): { text: string; tags: string[] } {
  const dishText = mem.dishes.map((d) => d.name + " " + d.tasteTags.join(" ")).join(" ");
  return {
    text: `${mem.restaurantName} ${mem.area || ""} ${dishText}`,
    tags: mem.tasteTags,
  };
}

const TAG_WEIGHT = 2.5;

// Returns { relevance, score }. `relevance` is text/tag overlap only — the
// filter gate. `score` adds a small recency nudge for ordering. Recency alone
// must NEVER keep an irrelevant memory (that was a real bug), so it is excluded
// from `relevance`.
function scoreMemory(
  q: Map<string, number>,
  qTags: Set<string>,
  mem: Memory
): { relevance: number; score: number } {
  const f = memoryFields(mem);
  const memBag = bag(tokenize(f.text));
  let overlap = 0;
  let qNorm = 0;
  for (const [tok, c] of q) {
    qNorm += c * c;
    if (memBag.has(tok)) overlap += c * Math.min(c, memBag.get(tok)!);
  }
  let tagBoost = 0;
  for (const tag of mem.tasteTags) if (qTags.has(tag)) tagBoost += TAG_WEIGHT;

  const denom = Math.sqrt(qNorm || 1) * Math.sqrt(memBag.size || 1);
  const relevance = (denom ? overlap / denom : 0) + tagBoost;
  const recency = 1 / (1 + (Date.now() - mem.ts) / (180 * 86_400_000));
  return { relevance, score: relevance + recency * 0.15 };
}

export interface RetrieveOpts {
  k?: number;
  /** Restrict to one restaurant (for "上次去 X 食咩" style recall). */
  restaurantId?: string;
  /** Extra taste tags to weight (e.g. parsed from the query). */
  tags?: string[];
}

/**
 * Retrieve the top-k most relevant memories for a query. NEVER returns more than
 * MAX_K. Returns [] when there is nothing relevant.
 */
export function retrieve(
  query: string,
  memories: Memory[],
  opts: RetrieveOpts = {}
): Retrieved[] {
  const k = Math.min(opts.k ?? DEFAULT_K, MAX_K);
  const pool = opts.restaurantId
    ? memories.filter((m) => m.restaurantId === opts.restaurantId)
    : memories;
  const qBag = bag([...tokenize(query), ...(opts.tags ?? [])]);
  const qTags = new Set([...(opts.tags ?? []), ...tokenize(query)]);

  const scored = pool.map((memory) => {
    const { relevance, score } = scoreMemory(qBag, qTags, memory);
    return { memory, score, relevance };
  });

  // Restaurant-scoped recall ("上次去 X 食咩") returns that restaurant's visits
  // regardless of text overlap. Open queries require real relevance.
  const kept = opts.restaurantId
    ? scored
    : scored.filter((r) => r.relevance > 0.02);

  return kept
    .sort((a, b) => b.score - a.score)
    .slice(0, k)
    .map(({ memory, score, relevance }) => ({ memory, score, relevance }));
}

/** Aggregate the user's dominant taste tags across memories (for recommend). */
export function topTasteTags(memories: Memory[], n = 4): string[] {
  const counts = new Map<string, number>();
  for (const m of memories)
    for (const t of m.tasteTags) counts.set(t, (counts.get(t) || 0) + 1);
  return [...counts.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, n)
    .map(([t]) => t);
}
