// Vision (MOCK MODE) — retrospective album scan + dish recognition.
//
// NO API key, NO network, NO spend. scanAlbumMock() returns canned "detected"
// visits that resolve to REAL FEHD restaurants (so seeded memory points at real
// places), giving the minute-1 "佢識我食過乜" feel. recognizeDishMock() backs the
// 影碟 log. The real seam is a vision API (image → dish/restaurant); the shapes
// here match what that would return, so wiring a key later is local.
//
// Accuracy note (§5.2): confidence is deliberately < 1 on dish-level guesses —
// "餐廳層準、餐點層矇" — and the UI offers confirm/edit rather than asserting.

import type { Catalogue, Dish, Memory } from "./types";
import { findByName } from "./catalogue";

export const VISION_MODE: "mock" | "real" = "mock";

interface CannedVisit {
  finds: string[]; // try these names against the catalogue, in order
  dishes: Dish[];
  tags: string[];
  daysAgo: number;
  confidence: number;
}

