/** Build initial memories from a mock album scan. Resolves each canned visit to
 *  a real catalogue restaurant; skips any that don't resolve. */
export function scanAlbumMock(cat: Catalogue, now = Date.now()): Omit<Memory, "id">[] {
  const out: Omit<Memory, "id">[] = [];
  for (const v of CANNED_ALBUM) {
    let r = null;
    for (const f of v.finds) {
      r = findByName(cat, f);
      if (r) break;
    }
    if (!r) continue;
    out.push({
      ts: now - v.daysAgo * 86_400_000,
      restaurantId: r.id,
      restaurantName: r.name.tc || r.name.en,
      area: r.area,
      dishes: v.dishes,
      tasteTags: v.tags,
      source: "album",
      confidence: v.confidence,
    });
  }
  return out;
}

// Canned dish guesses for the 影碟 log (rotates). Confidence < 1 on purpose.
const CANNED_DISHES: Dish[] = [
  { name: "干炒牛河", tasteTags: ["港式", "麵", "鑊氣"] },
  { name: "楊枝甘露", tasteTags: ["甜品", "港式"] },
  { name: "豬骨拉麵", tasteTags: ["日式", "麵", "拉麵"] },
  { name: "菠蘿油", tasteTags: ["港式", "茶餐廳"] },
];
let dishIdx = 0;

export function recognizeDishMock(): { dish: Dish; confidence: number } {
  const dish = CANNED_DISHES[dishIdx % CANNED_DISHES.length];
  dishIdx += 1;
  return { dish, confidence: 0.6 };
}
