// 飲食記憶 — app entry. Framework-free. v1 mock-first: FEHD catalogue + album
// memory + recall. No accounts, no real API (vision/LLM mocked).
import "./styles.css";
import type { Catalogue, Memory, Restaurant, Retrieved } from "./types";
import { el, clear, ago } from "./dom";
import { loadCatalogue, searchRestaurants } from "./catalogue";
import {
  allMemories,
  addMemories,
  addMemory,
  deleteMemory,
  deleteAllMemories,
  memoryCount,
} from "./memory";
import { scanAlbumMock, recognizeDishMock } from "./vision";
import { answerRecall, type RecallResult } from "./recall";
import { hasConsent, grantConsent } from "./consent";

interface UIState {
  cat: Catalogue | null;
  answer: RecallResult | null;
  lastQuery: string;
  scanning: boolean;
}
const state: UIState = { cat: null, answer: null, lastQuery: "", scanning: false };

// ---- boot ------------------------------------------------------------------

async function boot(): Promise<void> {
  const app = document.getElementById("app")!;
  app.replaceChildren(el("div", { class: "loading", text: "載入緊…" }));
  try {
    state.cat = await loadCatalogue(import.meta.env.BASE_URL);
  } catch (err) {
    app.replaceChildren(
      el("div", { class: "error" }, "餐廳目錄載入失敗。", el("br"), String(err))
    );
    return;
  }
  if (!hasConsent()) {
    renderConsent();
    return;
  }
  render();
}

// ---- consent gate ----------------------------------------------------------

function renderConsent(): void {
  const app = document.getElementById("app")!;
  clear(app);
  app.appendChild(
    el(
      "div",
      { class: "consent" },
      el("div", { class: "consent-card" },
        el("div", { class: "c-logo", text: "🍜" }),
        el("h1", { text: "飲食記憶" }),
        el("p", { class: "c-lead", text: "你嘅私人飲食記憶 — 去過邊、食過乜、鍾意咩味。" }),
        el("ul", { class: "c-points" },
          el("li", { text: "🔒 記憶只存喺你部機，你完全擁有。" }),
          el("li", { text: "🗑️ 隨時一按刪清晒。" }),
          el("li", { text: "🚫 永遠唔會賣你嘅資料。" })
        ),
        el("p", { class: "c-note", text: "（v1 示範版：全部資料存喺本機，唔會上傳。日後如接 AI 功能，會另外問你同意先。）" }),
        el("button", {
          class: "c-agree",
          text: "明白，開始",
          onclick: () => {
            grantConsent();
            render();
          },
        })
      )
    )
  );
}

// ---- home ------------------------------------------------------------------

function render(): void {
  const app = document.getElementById("app")!;
  clear(app);
  app.appendChild(header());
  app.appendChild(askSection());
  if (state.answer) app.appendChild(answerCard(state.answer));

  const mems = allMemories();
  if (mems.length === 0) app.appendChild(onboardCard());
  app.appendChild(logSection());
  app.appendChild(memoryTimeline(mems));
  app.appendChild(catalogueSection());
  app.appendChild(footer());
}

function header(): HTMLElement {
  const n = memoryCount();
  return el(
    "header",
    { class: "app-header" },
    el("div", { class: "brand" },
      el("span", { class: "logo", text: "🍜" }),
      el("div", {},
        el("h1", { text: "飲食記憶" }),
        el("p", { class: "tagline", text: n > 0 ? `${n} 段記憶 · 生長緊` : "佢記得你食過乜" })
      )
    ),
    el("button", {
      class: "settings-btn",
      text: "⚙︎",
      "aria-label": "設定",
      onclick: openSettings,
    })
  );
}

// ---- ask (recall) ----------------------------------------------------------

function askSection(): HTMLElement {
  const input = el("input", {
    class: "ask-input",
    type: "text",
    placeholder: "問我：今晚食乜好？／上次去譚仔叫咗咩？",
    value: state.lastQuery,
  }) as HTMLInputElement;

  const run = () => {
    const q = input.value.trim();
    if (!q) return;
    state.lastQuery = q;
    state.answer = answerRecall(q, allMemories(), state.cat!);
    render();
  };
  input.addEventListener("keydown", (e) => {
    if ((e as KeyboardEvent).key === "Enter") run();
  });

  const chips = ["今晚食乜好？", "上次去譚仔叫咗咩？", "我鍾意食辣，有咩推介？"].map((c) =>
    el("button", {
      class: "ask-chip",
      text: c,
      onclick: () => {
        input.value = c;
        run();
      },
    })
  );

  return el(
    "section",
    { class: "ask-section" },
    el("p", { class: "ask-lead", text: "問我啖你嘅飲食記憶" }),
    el("div", { class: "ask-row" },
      input,
      el("button", { class: "ask-btn", text: "問", onclick: run })
    ),
    el("div", { class: "ask-chips" }, ...chips)
  );
}

function answerCard(a: RecallResult): HTMLElement {
  const bubble = el("div", { class: "answer-bubble" },
    el("p", { class: "answer-text" },
      ...a.text.split("\n").flatMap((line, i) => (i ? [el("br"), line] : [line]))
    )
  );
  if (a.cited.length) {
    bubble.appendChild(el("p", { class: "cite-label", text: `我睇返 ${a.cited.length} 段相關記憶：` }));
    bubble.appendChild(citedList(a.cited));
  } else {
    bubble.appendChild(el("p", { class: "cite-label muted", text: "（唔會老作 — 冇相關記憶就照直講）" }));
  }
  return el("section", { class: "answer-card kind-" + a.kind },
    el("div", { class: "answer-avatar", text: "🍜" }),
    bubble
  );
}

function citedList(cited: Retrieved[]): HTMLElement {
  const wrap = el("div", { class: "cited" });
  for (const c of cited) {
    wrap.appendChild(
      el("div", { class: "cited-item" },
        el("span", { class: "ci-name", text: c.memory.restaurantName }),
        el("span", { class: "ci-meta", text: `${ago(c.memory.ts)} · ${c.memory.dishes.map((d) => d.name).join("、")}` })
      )
    );
  }
  return wrap;
}

// ---- onboarding: retrospective album scan ----------------------------------

// A hidden <input type=file>. `camera` → capture from camera (single);
// otherwise → photo-library picker (with `multiple`). On mobile, iOS PWAs can't
// read the whole album, so the retrospective entry is an explicit multi-PICK —
// we never pretend to auto-scan everything.
function makeFileInput(
  opts: { multiple?: boolean; camera?: boolean },
  onFiles: (files: FileList) => void
): HTMLInputElement {
  const attrs: Record<string, string | boolean> = {
    type: "file",
    accept: "image/*",
    class: "hidden-file",
  };
  if (opts.multiple) attrs.multiple = true;
  if (opts.camera) attrs.capture = "environment";
  const input = el("input", attrs) as HTMLInputElement;
  input.addEventListener("change", () => {
    if (input.files && input.files.length) onFiles(input.files);
    input.value = ""; // allow re-picking the same file
  });
  return input;
}

function onboardCard(): HTMLElement {
  const albumIn = makeFileInput({ multiple: true }, (f) => runAlbumImport(f.length));
  return el(
    "section",
    { class: "onboard" },
    el("div", { class: "ob-emoji", text: "📸" }),
    el("h2", { text: "揀返你食過嘢嘅相" }),
    el("p", { text: "喺相簿揀幾張食物相，我幫你砌返去過邊、食過乜 — 唔使等三個星期。" }),
    el("button", {
      class: "ob-btn" + (state.scanning ? " busy" : ""),
      text: state.scanning ? "認緊…" : "揀相簿相片",
      onclick: () => albumIn.click(),
    }),
    albumIn,
    el("p", { class: "ob-note", text: "你揀邊幾張，我先睇邊幾張 — iOS 讀唔到成個相簿，唔會自動掃晒。（認相係 mock，唔上傳、唔收費。）" })
  );
}

async function runAlbumImport(pickedCount: number): Promise<void> {
  if (state.scanning) return;
  state.scanning = true;
  render();
  await new Promise((r) => setTimeout(r, 700)); // mimic recognition
  // Mock: recognise as many visits as photos picked (canned, real restaurants).
  const all = scanAlbumMock(state.cat!);
  const chosen = all.slice(0, Math.max(1, Math.min(pickedCount, all.length)));
  addMemories(chosen);
  state.scanning = false;
  toast(`認返 ${chosen.length} 餐 🎉`);
  render();
}

// ---- persistent log (影單 / 影碟) ------------------------------------------

function logSection(): HTMLElement {
  // Three collection entry points (§ spec): 相簿 (multi-pick), 影單, 影碟 (camera).
  const albumIn = makeFileInput({ multiple: true }, (f) => runAlbumImport(f.length));
  const receiptIn = makeFileInput({ camera: true }, (f) => startDishLog("receipt", f[0]));
  const dishIn = makeFileInput({ camera: true }, (f) => startDishLog("dish", f[0]));
  return el(
    "section",
    { class: "log-section" },
    el("h3", { class: "sec-title", text: "記低今餐" }),
    el("div", { class: "log-btns" },
      el("button", { class: "log-btn", text: "📷 揀相簿", onclick: () => albumIn.click() }),
      el("button", { class: "log-btn", text: "🧾 影單", onclick: () => receiptIn.click() }),
      el("button", { class: "log-btn", text: "🍽️ 影碟", onclick: () => dishIn.click() })
    ),
    albumIn, receiptIn, dishIn
  );
}

// Mock recognize → confirm/edit (§5.2) → pick restaurant → save.
function startDishLog(source: "receipt" | "dish", file?: File): void {
  const { dish, confidence } = recognizeDishMock();
  const overlay = el("div", { class: "modal-overlay" });
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) overlay.remove();
  });

  const dishName = el("input", { class: "log-dish", type: "text", value: dish.name }) as HTMLInputElement;
  const searchInput = el("input", { class: "log-search", type: "text", placeholder: "喺邊間食？搜尋餐廳…" }) as HTMLInputElement;
  const results = el("div", { class: "log-results" });
  let picked: Restaurant | null = null;
  const pickedLabel = el("p", { class: "log-picked", text: "" });

  searchInput.addEventListener("input", () => {
    clear(results);
    const rs = searchRestaurants(state.cat!, searchInput.value, 6);
    for (const r of rs) {
      results.appendChild(
        el("button", {
          class: "log-result",
          text: `${r.name.tc}　·　${r.area}`,
          onclick: () => {
            picked = r;
            pickedLabel.textContent = `✓ ${r.name.tc}（${r.area}）`;
            clear(results);
            searchInput.value = r.name.tc;
          },
        })
      );
    }
  });

  const save = el("button", {
    class: "log-save",
    text: "儲入記憶",
    onclick: () => {
      if (!picked) {
        pickedLabel.textContent = "請先揀返間餐廳。";
        return;
      }
      const name = dishName.value.trim() || dish.name;
      addMemory({
        ts: Date.now(),
        restaurantId: picked.id,
        restaurantName: picked.name.tc || picked.name.en,
        area: picked.area,
        dishes: [{ name, tasteTags: dish.tasteTags }],
        tasteTags: dish.tasteTags,
        source,
        confidence,
      });
      overlay.remove();
      toast("已加入記憶 ✓");
      render();
    },
  });

  // Preview the captured photo (from the real file input) for a "似真" feel.
  const preview = file
    ? (el("img", { class: "log-preview", src: URL.createObjectURL(file), alt: "" }) as HTMLImageElement)
    : null;
  if (preview) preview.addEventListener("load", () => URL.revokeObjectURL(preview.src));

  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: () => overlay.remove() }),
      el("h2", { class: "log-title", text: source === "receipt" ? "認到張單" : "認到碟嘢" }),
      preview,
      el("p", { class: "log-conf", text: `AI 認到：${dish.name}（信心 ${Math.round(confidence * 100)}%）— 改得，最緊要啱。` }),
      el("label", { class: "log-lbl", text: "食咗咩" }),
      dishName,
      el("label", { class: "log-lbl", text: "邊間餐廳" }),
      searchInput,
      results,
      pickedLabel,
      save
    )
  );
  document.body.appendChild(overlay);
}

// ---- memory timeline -------------------------------------------------------

function memoryTimeline(mems: Memory[]): HTMLElement {
  const section = el("section", { class: "timeline" },
    el("h3", { class: "sec-title", text: `我嘅飲食記憶（${mems.length}）` })
  );
  if (mems.length === 0) {
    section.appendChild(el("p", { class: "empty", text: "未有記憶。掃相簿或者影一餐，就開始生長。" }));
    return section;
  }
  for (const m of mems) {
    section.appendChild(
      el("div", { class: "mem" },
        el("div", { class: "mem-main" },
          el("div", { class: "mem-top" },
            el("span", { class: "mem-name", text: m.restaurantName }),
            el("span", { class: "mem-ago", text: ago(m.ts) })
          ),
          m.area ? el("div", { class: "mem-area", text: "📍 " + m.area }) : null,
          el("div", { class: "mem-dishes", text: m.dishes.map((d) => d.name).join("、") || "—" }),
          el("div", { class: "mem-tags" },
            ...m.tasteTags.slice(0, 5).map((t) => el("span", { class: "mem-tag", text: t })),
            el("span", { class: "mem-src", text: srcLabel(m.source) }),
            m.confidence < 0.75 ? el("span", { class: "mem-fuzzy", text: "大概印象" }) : null
          )
        ),
        el("button", {
          class: "mem-del",
          text: "✕",
          "aria-label": "刪除",
          onclick: () => {
            deleteMemory(m.id);
            render();
          },
        })
      )
    );
  }
  return section;
}

function srcLabel(s: Memory["source"]): string {
  return { album: "📸 相簿", receipt: "🧾 單", dish: "🍽️ 碟", manual: "✍️ 手動" }[s];
}

// ---- catalogue search (基本盤) ---------------------------------------------

function catalogueSection(): HTMLElement {
  const results = el("div", { class: "cat-results" });
  const input = el("input", {
    class: "cat-input",
    type: "search",
    placeholder: `搜尋全港餐廳（${state.cat?.count ?? 0} 間）`,
  }) as HTMLInputElement;
  let deb: ReturnType<typeof setTimeout> | null = null;
  input.addEventListener("input", () => {
    if (deb) clearTimeout(deb);
    deb = setTimeout(() => {
      clear(results);
      const rs = searchRestaurants(state.cat!, input.value, 12);
      for (const r of rs) {
        results.appendChild(
          el("div", { class: "cat-item" },
            el("span", { class: "cat-name", text: r.name.tc }),
            el("span", { class: "cat-area", text: `${r.area} · ${r.region}` })
          )
        );
      }
    }, 130);
  });
  return el("section", { class: "cat-section" },
    el("h3", { class: "sec-title", text: "全港餐廳目錄" }),
    input,
    results
  );
}

// ---- settings (privacy: delete all) ----------------------------------------

function openSettings(): void {
  const overlay = el("div", { class: "modal-overlay" });
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) overlay.remove();
  });
  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: () => overlay.remove() }),
      el("h2", { text: "設定 · 私隱" }),
      el("p", { class: "set-line", text: `你有 ${memoryCount()} 段記憶，全部存喺你部機。` }),
      el("p", { class: "set-line muted", text: "你完全擁有呢啲資料。刪除係即時、永久。" }),
      el("button", {
        class: "danger-btn",
        text: "🗑️ 刪除所有記憶",
        onclick: () => {
          if (confirm("確定刪除全部飲食記憶？呢個動作無得復原。")) {
            deleteAllMemories();
            state.answer = null;
            overlay.remove();
            toast("已刪除所有記憶");
            render();
          }
        },
      })
    )
  );
  document.body.appendChild(overlay);
}

function footer(): HTMLElement {
  return el("footer", { class: "app-footer" },
    el("p", { text: "餐廳目錄來源：食環署（FEHD）持牌食肆 open data" }),
    el("p", { class: "src", text: "v1 示範 · AI 功能為 mock（未接真 API）" })
  );
}

// ---- toast -----------------------------------------------------------------

let toastTimer: ReturnType<typeof setTimeout> | null = null;
function toast(text: string): void {
  document.querySelector(".toast")?.remove();
  const node = el("div", { class: "toast", text });
  document.body.appendChild(node);
  if (toastTimer) clearTimeout(toastTimer);
  toastTimer = setTimeout(() => node.remove(), 2600);
}

boot();
